result = list(map(add, numbers))
print(result) # Output: [2, 3, 4, 5, 6]

# Use a lambda function to create an anonymous function that adds two numbers
add_lambda = lambda x, y: x + y
result = add_lambda(2, 3)
print(result) # Output: 5
```

